/// <summary>
/// enable form in edit mode after button click 
/// Header/Line items should be frozen once P/S agreement/order is confirmed by user. It cannot be edited.
/// </summary>
/// <param name="sender">FormControl sender</param>
/// <param name="e">FormControlEventArgs e</param>
[FormControlEventHandler(formControlStr(SalesAgreement, ETGChangeReqButton), FormControlEventType::Clicked)]
public static void ETGChangeReqButton_OnClicked(FormControl sender, FormControlEventArgs e)
{
    sender.formRun().design(ViewEditMode::Edit);
    FormDataSource                   salesAgreementHeader_ds   = sender.formRun().dataSource('salesAgreementHeader');
    SalesAgreementHeader             salesAgreementHeader      = salesAgreementHeader_ds.cursor();
    salesAgreementHeader.AgreementState = AgreementState::OnHold;
    //NS, DLT ,27/05/2025 Shreelekha header items should be enable when change request button is clicked
    salesAgreementHeader_ds.write();
    salesAgreementHeader_ds.allowEdit(true);
    salesAgreementHeader_ds.allowCreate(true);
    salesAgreementHeader_ds.allowDelete(true);
    //salesAgreementHeader_ds.refresh();
    //salesAgreementHeader_ds.active();
    //salesAgreementHeader_ds.reread();
    //salesAgreementHeader_ds.research();
    //NE, DLT ,27/05/2025 Shreelekha header items should be enable when change request button is clicked

    //NS, DLT ,27/05/2025 Shreelekha Line items should be enable when change request button is clicked
    FormDataSource salesAgreementLine_ds = sender.formRun().dataSource('Aline');
    salesAgreementLine_ds.allowEdit(true);
    salesAgreementLine_ds.allowCreate(true);
    salesAgreementLine_ds.allowDelete(true);
    //salesAgreementLine_ds.refresh();
    //salesAgreementLine_ds.active();

    FormRun             element       = sender.formRun();
    FormControl         LineViewLineDetailsctrl    = element.design().controlName('LineViewLineDetails');
    LineViewLineDetailsctrl.allowEdit(true);
    LineViewLineDetailsctrl.enabled(true);

    FormControl         OverDeliveryPctCtrl    = element.design().controlName('OverDeliveryPct');
    OverDeliveryPctCtrl.allowEdit(true);
    OverDeliveryPctCtrl.enabled(true);
    FormControl         UnderDeliveryPctCtrl    = element.design().controlName('UnderDeliveryPct');
    UnderDeliveryPctCtrl.allowEdit(true);
    UnderDeliveryPctCtrl.enabled(true);

    salesAgreementHeader_ds.research(true);


    //NE, DLT ,27/05/2025 Shreelekha Line items should be enable when change request button is clicked
}

 /// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesAgreement, ButtonConfirmationETG), FormControlEventType::Clicked)]
public static void ButtonConfirmationETG_OnClicked(FormControl sender, FormControlEventArgs e)
{


    Object                           formRun;
    FormRun                          formrunloc = sender.formRun();
    FormDataSource                   SalesAgreementHeader_ds   = sender.formRun().dataSource('SalesAgreementHeader');
    SalesAgreementHeader             SalesAgreementHeader      = SalesAgreementHeader_ds.cursor();
    FormDataSource                   Aline_ds                  = sender.formRun().dataSource('Aline');
    //AgreementLineQuantityCommitment  aline                     = Aline_ds.cursor();
    //Shreelekha
    AgreementLineQuantityCommitment aline;
    select firstonly aline
        where aline.RecId == Aline_ds.cursor().RecId;

    FormDataSource                   ETG_AgreementLineQualityGrp_ds = sender.formRun().dataSource('ETG_AgreementLineQualityGrp');
    ETG_AgreementLineQualityGrp      agreementLineQualityGrp   = ETG_AgreementLineQualityGrp_ds.cursor();
    AgreementLineQuantityCommitment  purchAgreementLine;
    ETG_ChargeCodes                  chargeCodes;
    int                              i = 1;
    Args                             args = new Args();
    boolean                          isContinue = true;
    #task
    FormDataSource                   inventDim_ds   = sender.formRun().dataSource('InventDim');
    InventDim                        inventDim      = inventDim_ds.cursor();
    DefaultDimensionView            defaultDimView;
    //DimensionHierarchyView      dimensionHierarchy;
    DimensionHierarchy              dimensionHierarchy;
    DimensionHierarchyLevel         dimensionHierarchyLevel;
    DimensionAttribute              dimAttribute;
    Description255                  emptyDimension;

    while select inventDim
        where inventDim.inventDimId == aline.InventDimId
        && inventDim.DataAreaId == aline.InventDimDataAreaId
    {

        if(inventDim.InventSiteId == '' && inventDim.InventLocationId == '')
        {
            throw error("@ETG:SiteWarehouseMandatory");
        }
        if(inventDim.InventSiteId == '')
        {
            throw error("@ETG:SiteMandatory");
        }
        if( InventDim.InventLocationId == '')
        {
            throw error("@ETG:WarehouseMandatory");
        }
    }

    if (ETGACFParameters::find().EnableContractFDAutomation && SalesAgreementHeader.ETG_IsThirdParty == NoYes::No)
    {
        ETGContractFDDerivedDimCreate derivedDimCreate = new ETGContractFDDerivedDimCreate();
        derivedDimCreate.validate(SalesAgreementHeader);
    }

    select firstonly RecId from chargeCodes
        where chargeCodes.PurchNumberSequence == SalesAgreementHeader.SalesNumberSequence;

    if(ETG_Parameters::find().ETGIsDimensionValidationRequired == NoYes::Yes)
    {
        //select firstonly RecId from dimensionHierarchy
        //    where dimensionHierarchy.StructureType == DimensionHierarchyType::AccountStructure
        //        && dimensionHierarchy.Status == DimensionHierarchyConstraintStatus::Active
        //        && dimensionHierarchy.UserLanguageId == CompanyInfo::languageId();

        select firstonly RecId from dimensionHierarchy
            where dimensionHierarchy.StructureType == DimensionHierarchyType::AccountStructure
                 && dimensionHierarchy.IsDraft == NoYes::No;

        while select DimensionAttribute from dimensionHierarchyLevel
            where dimensionHierarchyLevel.DimensionHierarchy == dimensionHierarchy.RecId
        join dimAttribute
            where dimAttribute.RecId == dimensionHierarchyLevel.DimensionAttribute
                && dimAttribute.Type != DimensionAttributeType::MainAccount
        notexists join defaultDimView
            where defaultDimView.Name ==  dimAttribute.Name
                && defaultDimView.DefaultDimension == SalesAgreementHeader.DefaultDimension
        {
            if(emptyDimension)
            {
                emptyDimension = emptyDimension + ',' + dimAttribute.Name;
            }
            else
            {
                emptyDimension = dimAttribute.Name;
            }
        }

        if(isContinue && emptyDimension)
        {
            if(Box::yesNoAxaptaForm(strFmt('Financial dimensions - %1 are not filled in. Do you want to update? ',emptyDimension), DialogButton::Yes) == DialogButton::Yes)
            {
                isContinue = false;
            }
        }
    }


    if(SalesAgreementHeader.ETG_PurchAgreementIdTP)
    {
        if( Box::yesNo('@ETG:UnitPriceandPortValidation',DialogButton::Yes) == DialogButton::Yes)
        {
            isContinue = false;
        }
    }
    if(isContinue && !chargeCodes)
    {
        if( Box::yesNo('@ETG:EstimationChargesValidation', DialogButton::yes) == DialogButton::yes)
        {
            isContinue = false;
            args.record(SalesAgreementHeader);
            args.name(menuItemDisplayStr(ETG_ChargeCodes));
            formRun = classfactory.formRunClass(args);
            formRun.init();
            formRun.run();
            formRun.wait();
        }
    }
    if(isContinue && !agreementLineQualityGrp)
    {
        if(Box::yesNo('@ETG:QualitySpecValidation', DialogButton::Yes) == DialogButton::Yes)
        {
            isContinue = false;
        }
    }
    if(isContinue)
    {
        args.record(SalesAgreementHeader);

        new MenuFunction(menuItemActionStr(SalesAgreementConfirm), MenuItemType::Action).run(args);
    }
    //NS, DLT ,25/03/2025 Once the agreement is confirmed Same FD value should appear automatically update DerivedDimCreate.
    if (ETGACFParameters::find().EnableContractFDAutomation && SalesAgreementHeader.ETG_IsThirdParty == NoYes::No)
     {
        ETGContractFDDerivedDimCreate derivedDimCreate = new ETGContractFDDerivedDimCreate();
        derivedDimCreate.createCustomFinDimContract(SalesAgreementHeader);
        derivedDimCreate.ContractFDDerivedDimCreate(SalesAgreementHeader);
     }
    //NE, DLT ,25/03/2025 Once the agreement is confirmed Same FD value should appear automatically update DerivedDimCreate.


    //NS, DLT ,11032025, Provisional charges IncoTerms

    //if(ETGACFParameters::find().EnableProvisionalCharges &&
    //            AgreementClassification::find(SalesAgreementHeader.AgreementClassification).ETGIncoTerms == NoYes::Yes)
    //{
    //    if(!SalesAgreementHeader.agreementHeaderDefault().DeliveryTerm)
    //    {
    //        throw error(strFmt("Terms of delivery is mandatory for agreement %1", SalesAgreementHeader.SalesNumberSequence));
    //    }
    //    ETGProvisionalChargesCreate::createChargesSales(SalesAgreementHeader);
    //}
    //NE, DLT ,11032025, Provisional charges IncoTerms





    formrunloc.task(#taskRefresh);
}

[FormDataSourceEventHandler(formDataSourceStr(SalesAgreementCreate, SalesAgreementHeader), FormDataSourceEventType::Written)]
public static void SalesAgreementHeader_OnWritten(FormDataSource sender, FormDataSourceEventArgs e)
{
    ETG_SalesAgreementHeader SalesAgreementHeaderTP;//   = sender.cursor();;
    FormDataSource              SalesAgreementHeader_ds   = sender.formRun().dataSource('SalesAgreementHeader');
    SalesAgreementHeader        SalesAgreementHeader        =  SalesAgreementHeader_ds.cursor();//sender.cursor();
    FormDataSource              AgreementHeaderDefault_ds   = sender.formRun().dataSource('AgreementHeaderDefault');
    AgreementHeaderDefault      agreementHeaderDefault      = AgreementHeaderDefault_ds.cursor();


    SalesAgreementHeaderTP.SalesAgreementId      = SalesAgreementHeader.SalesNumberSequence;
    SalesAgreementHeaderTP.SellerAccountNum      = curExt();
    SalesAgreementHeaderTP.SellerDeliveryAddress = CompanyInfo::findDataArea(curExt()).postalAddress().RecId;
    SalesAgreementHeaderTP.SellerBank            = CompanyInfo::findDataArea(curExt()).Bank;
  //  SalesAgreementHeaderTP.SellerBankDeliveryAddress = BankAccountTable::findByCompany(curExt(),SalesAgreementHeaderTP.BuyerBank).postalAddress().RecId;

    SalesAgreementHeaderTP.BuyerAccountNum       = SalesAgreementHeader.CustAccount;
    SalesAgreementHeaderTP.BuyerDeliveryAddress  = CustTable::find(salesAgreementHeader.CustAccount).postalAddress().RecId;
    SalesAgreementHeaderTP.BuyerBank             = CustTable::find(salesAgreementHeader.CustAccount).BankAccount;
    SalesAgreementHeaderTP.TermPaymDescription   = PaymTerm::find(agreementHeaderDefault.PaymentTerms).Description;
    SalesAgreementHeaderTP.TermsOfDelDescription = DlvTerm::find(agreementHeaderDefault.DeliveryTerm).Txt;
 //   SalesAgreementHeaderTP.BuyerBankDeliveryAddress =  CustBankAccount::find(salesAgreementHeader.CustAccount,SalesAgreementHeaderTP.SellerBank).Location;
    SalesAgreementHeaderTP.insert();
}

