        ETG_SalesAgreementHeader SalesAgreementHeaderETG = sender.dataSourceObject().cursor();

        sysTableLookup = SysTableLookup::newParameters(tableNum(CustBankAccount), sender);
        queryBuildDataSource = query.addDataSource(tableNum(CustBankAccount));
        queryBuildDataSource.addRange(fieldNum(CustBankAccount, CustAccount)).value(queryValue(SalesAgreementHeaderETG.BuyerAccountNum));
        sysTableLookup.parmQuery(query);
        sysTableLookup.addLookupField(fieldNum(CustBankAccount, AccountID));
        sysTableLookup.addLookupField(fieldNum(CustBankAccount,Name ));

        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();

        FormControlCancelableSuperEventArgs cancelableArgs = e as FormControlCancelableSuperEventArgs;
        cancelableArgs.CancelSuperCall();
    }

