    /// <param name="sender"></param>
    /// <param name="e"></param>


     [FormControlEventHandler(formControlStr(SalesAgreement, Through), FormControlEventType::Lookup)]
    public static void Through_OnLookup(FormControl sender, FormControlEventArgs e)
    {

        SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tableNum(VendTable),sender);
        Query                   q   = new Query();
        QueryBuildDataSource    qbds,qbds1,qbds2,qbds3;
        QueryBuildRange         qbr;

        qbds   = q.addDataSource(tableNum(VendTable));
        qbds2 = qbds.addDataSource(tableNum(VendGroup));
        qbds2.joinMode(JoinMode::InnerJoin);
        qbds2.relations(true);
        qbds3    = qbds.addDataSource(tableNum(DirPartyTable)) ;
        qbds3.joinMode(JoinMode::InnerJoin);
        qbds3.addLink(fieldNum(VendTable, Party), fieldNum(DirPartyTable, RecId));


        qbr     = qbds2.addRange(fieldNum(VendGroup,ETG_Broker));
        qbr.value(queryValue(NoYes::Yes));

        sysTableLookup.addLookupfield(fieldNum(VendTable,AccountNum));
        sysTableLookup.addLookupfield(fieldNum(VendTable,vendgroup));
        sysTableLookup.addLookupfield(fieldNum(VendTable, Party), false);

        SysTableLookup.parmQuery(q);
        SysTableLookup.performFormLookup();
        FormControlCancelableSuperEventArgs ce = e as FormControlCancelableSuperEventArgs;

        ce.CancelSuperCall();
    }

