/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesAgreement, Notifytodifferentparty), FormControlEventType::Modified)]
public static void Notifytodifferentparty_OnModified(FormControl sender, FormControlEventArgs e)
{
    ETG_SalesAgreementHeader salesAgreementHeaderETG = sender.formRun().dataSource().cursor();
    FormRun             element       = sender.formRun(); //form element
    FormControl         NotifyName   = element.design(0).controlName("NotifyName");
    FormControl         NotifyAddress   = element.design(0).controlName("NotifyAddress");

    if(salesAgreementHeaderETG.Notifytodifferentparty == NoYes::Yes)// && salesAgreementHeaderETG.Consignee && salesAgreementHeaderETG.OnAccountOf)
    {
        NotifyName.enabled(true);
        NotifyAddress.enabled(true);
    }
    else if(salesAgreementHeaderETG.Notifytodifferentparty == NoYes::No)// && salesAgreementHeaderETG.Consignee && salesAgreementHeaderETG.OnAccountOf)
    {
        salesAgreementHeaderETG.Name = "";
        salesAgreementHeaderETG.Address = "";
        NotifyName.enabled(false);
        NotifyAddress.enabled(false);
    }
}

[FormControlEventHandler(formControlStr(SalesAgreement, ShipmentTabPage), FormControlEventType::PageActivated)]
public static void ShipmentTabPage_OnPageActivated(FormControl sender, FormControlEventArgs e)
{
    ETG_SalesAgreementHeader salesAgreementHeaderETG = sender.formRun().dataSource().cursor();
    FormRun             element       = sender.formRun(); //form element
    FormControl         NotifyName   = element.design(0).controlName("NotifyName");
    FormControl         NotifyAddress   = element.design(0).controlName("NotifyAddress");

    if(salesAgreementHeaderETG.Notifytodifferentparty == NoYes::Yes)// && salesAgreementHeaderETG.Consignee && salesAgreementHeaderETG.OnAccountOf)
    {
        NotifyName.enabled(true);
        NotifyAddress.enabled(true);
    }
    else if(salesAgreementHeaderETG.Notifytodifferentparty == NoYes::No)// && salesAgreementHeaderETG.Consignee && salesAgreementHeaderETG.OnAccountOf)
    {
        salesAgreementHeaderETG.Name = "";
        salesAgreementHeaderETG.Address = "";
        NotifyName.enabled(false);
        NotifyAddress.enabled(false);
    }

}

[FormControlEventHandler(formControlStr(SalesAgreement, BuyerBankString), FormControlEventType::Modified)]
public static void BuyerBankString_OnModified(FormControl sender, FormControlEventArgs e)
{
    ETG_SalesAgreementHeader SalesAgreementHeaderETG = sender.formRun().dataSource(FormDataSourcestr(SalesAgreement, ETG_SalesAgreementHeader)).cursor();
    FormDataSource      ETG_SalesAgreementHeader_ds =  sender.formRun().dataSource(FormDataSourcestr(SalesAgreement, ETG_SalesAgreementHeader));
    CustBankAccount                              buyerBank;

    buyerBank     = CustBankAccount::find(SalesAgreementHeaderETG.BuyerAccountNum,SalesAgreementHeaderETG.BuyerBank);
    if(buyerBank)
        SalesAgreementHeaderETG.BuyerSecondaryBank = buyerBank.AccountNum + '\n'+buyerBank.SWIFTNo+'\n'+LogisticsPostalAddress::findByLocation(buyerBank.location).Address;
    else
        SalesAgreementHeaderETG.BuyerSecondaryBank = '';

    if (SalesAgreementHeaderETG.Buyersecondarybank == '' || SalesAgreementHeaderETG.BuyerBank == '')
    {
        ETG_SalesAgreementHeader_ds.object(fieldNum(ETG_SalesAgreementHeader, BuyerSecondaryBank)).allowEdit(true);
    }
    else
    {
        ETG_SalesAgreementHeader_ds.object(fieldNum(ETG_SalesAgreementHeader, BuyerSecondaryBank)).allowEdit(false);
    }


}

